// Script: generar_04_examenes_prevencion.js
// Que hace: agrega la pestaña "Examenes" dentro de app/prevencion/page.tsx,
// con:
//   - Subida de PDFs (maximo 8MB, solo PDF) a Supabase Storage bucket
//     "examenes", guardados en la ruta {user_id}/{mascota_id}/{archivo}.pdf
//   - Categoria fija (Hemograma, Perfil bioquimico, Orina, Corazon, Otro),
//     nombre opcional, fecha, y nota/resultado opcional
//   - Listado de examenes con boton "Ver / descargar PDF" que genera una
//     URL firmada temporal (valida 60 segundos, no se guarda en ningun lado)
//   - Boton para eliminar un examen (borra el archivo de Storage Y la fila
//     de la base de datos)
//
// IMPORTANTE: antes de correr este script, primero debes haber corrido
// el archivo 01_setup_examenes.sql en Supabase (bucket + tabla + politicas).
// Si no, vas a poder ver la pestaña pero subir un examen va a fallar.
//
// Como correrlo: node generar_04_examenes_prevencion.js
// Confirma que diga "OK: app/prevencion/page.tsx"

const fs = require('fs');
const path = require('path');

const filePath = path.join('app', 'prevencion', 'page.tsx');
const b64 = "";
const content = Buffer.from(b64, 'base64').toString('utf8');

const dir = path.dirname(filePath);
if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });

fs.writeFileSync(filePath, content, 'utf8');
console.log('OK: ' + filePath);
